import{_ as s,o as a,c as e,ag as r}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Tracium Ecosystem","description":"","frontmatter":{},"headers":[],"relativePath":"ecosystem/products.md","filePath":"ecosystem/products.md"}'),n={name:"ecosystem/products.md"};function o(d,t,c,i,p,l){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="tracium-ecosystem" tabindex="-1">Tracium Ecosystem <a class="header-anchor" href="#tracium-ecosystem" aria-label="Permalink to &quot;Tracium Ecosystem&quot;">​</a></h1><p>Tracium is not one application. It&#39;s an ecosystem of products that share the same execution data through UEF contracts.</p><h2 id="products" tabindex="-1">Products <a class="header-anchor" href="#products" aria-label="Permalink to &quot;Products&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Product</th><th>Codename</th><th>What It Does</th><th>Status</th></tr></thead><tbody><tr><td><strong>Tracium Engine</strong></td><td>CSE</td><td>Executes code via JDI, captures state, produces UEF</td><td>✅ Working</td></tr><tr><td><strong>Nerva</strong></td><td>—</td><td>Orchestrates sessions, persists traces, serves API</td><td>✅ Working</td></tr><tr><td><strong>Prism</strong></td><td>—</td><td>Visualizes traces with step-by-step playback</td><td>🔄 In Progress</td></tr><tr><td><strong>Atlas</strong></td><td>—</td><td>Analyzes repository structure, produces UGF</td><td>Planned</td></tr><tr><td><strong>Vector</strong></td><td>—</td><td>TypeScript SDK for programmatic access</td><td>Planned</td></tr><tr><td><strong>Pulse</strong></td><td>—</td><td>VS Code / JetBrains IDE integration</td><td>Planned</td></tr><tr><td><strong>Quanta</strong></td><td>—</td><td>Shared schemas (UEF, UGF)</td><td>✅ Defined</td></tr></tbody></table><h2 id="how-they-connect" tabindex="-1">How They Connect <a class="header-anchor" href="#how-they-connect" aria-label="Permalink to &quot;How They Connect&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User → Prism (or Pulse, or Vector)</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>       Nerva (API + trace store)</span></span>
<span class="line"><span>       ↙         ↘</span></span>
<span class="line"><span>Tracium Engine    Atlas</span></span>
<span class="line"><span>  (runtime)     (static)</span></span>
<span class="line"><span>       ↘         ↙</span></span>
<span class="line"><span>      Quanta (contracts)</span></span></code></pre></div><h2 id="shared-contracts" tabindex="-1">Shared Contracts <a class="header-anchor" href="#shared-contracts" aria-label="Permalink to &quot;Shared Contracts&quot;">​</a></h2><ul><li><strong>UEF</strong> — Universal Execution Format. Runtime traces.</li><li><strong>UGF</strong> — Unified Graph Format. Architecture graphs.</li></ul><p>Every product reads or writes these formats. No product owns execution logic except Engine. No product owns analysis logic except Atlas.</p>`,9)])])}const m=s(n,[["render",o]]);export{u as __pageData,m as default};
